import React, { useState, useEffect } from 'react';
import { BookOpen, Plus, MapPin, Calendar, Trash2, X, Save, Camera, Image as ImageIcon, Loader2 } from 'lucide-react';
import { supabase } from '../../services/supabaseClient';

function LogbookView() {
  const [entries, setEntries] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [newEntry, setNewEntry] = useState({ title: '', content: '', location: '', image: null });

  const fetchEntries = async () => {
    const { data } = await supabase.from('logbook').select('*').order('created_at', { ascending: false });
    if (data) setEntries(data);
  };

  useEffect(() => { fetchEntries(); }, []);

  const handleAddEntry = async () => {
    if (!newEntry.title || !newEntry.content) return;
    setUploading(true);
    let uploadedImageUrl = null;

    try {
      if (newEntry.image) {
        const fileName = `${Date.now()}-${newEntry.image.name}`;

        // 1. Försök ladda upp till Storage
        const { error: storageError } = await supabase.storage
          .from('logbook_images')
          .upload(fileName, newEntry.image);

        if (storageError) throw new Error("Storage-fel: " + storageError.message);

        // 2. Hämta URL
        const { data: urlData } = supabase.storage.from('logbook_images').getPublicUrl(fileName);
        uploadedImageUrl = urlData.publicUrl;
      }

      // 3. Spara i tabellen
      const { error: dbError } = await supabase.from('logbook').insert([{ 
        title: newEntry.title, 
        content: newEntry.content, 
        location: newEntry.location || 'Okänd plats',
        date: new Date().toLocaleDateString('sv-SE'),
        image_url: uploadedImageUrl 
      }]);

      if (dbError) throw new Error("Databas-fel: " + dbError.message);

      setShowAddModal(false);
      setNewEntry({ title: '', content: '', location: '', image: null });
      fetchEntries();
    } catch (err) {
      alert(err.message); // Detta visar exakt vad som går fel på telefonen!
    } finally {
      setUploading(false);
    }
  };

  return (
    <div style={{ padding: '20px', paddingBottom: '100px' }}>
      <h1 style={{color: '#2D5A27'}}><BookOpen /> Loggboken</h1>

      {entries.map(entry => (
        <div key={entry.id} style={{background:'#FFF', borderRadius:'15px', marginBottom:'15px', overflow:'hidden', boxShadow:'0 2px 5px rgba(0,0,0,0.1)'}}>
          {entry.image_url && <img src={entry.image_url} style={{width:'100%', height:'180px', objectFit:'cover'}} alt="minne" />}
          <div style={{padding:'15px'}}>
            <h3 style={{margin:0}}>{entry.title}</h3>
            <p style={{fontSize:'14px', color:'#636E72'}}>{entry.content}</p>
          </div>
        </div>
      ))}

      <button onClick={() => setShowAddModal(true)} style={btnStyle}><Plus /> Nytt minne</button>

      {showAddModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <h3>Spara nytt minne</h3>
            <input placeholder="Rubrik" style={inputStyle} onChange={e => setNewEntry({...newEntry, title: e.target.value})} />
            <textarea placeholder="Vad hände?" style={{...inputStyle, height:'60px'}} onChange={e => setNewEntry({...newEntry, content: e.target.value})} />

            <div style={{display:'flex', gap:'10px', marginBottom:'15px'}}>
              <label style={mediaBtn}><Camera size={18} /><input type="file" accept="image/*" capture="environment" style={{display:'none'}} onChange={e => setNewEntry({...newEntry, image: e.target.files[0]})} /> Kamera</label>
              <label style={mediaBtn}><ImageIcon size={18} /><input type="file" accept="image/*" style={{display:'none'}} onChange={e => setNewEntry({...newEntry, image: e.target.files[0]})} /> Galleri</label>
            </div>

            <button onClick={handleAddEntry} disabled={uploading} style={saveBtn}>
              {uploading ? <Loader2 className="animate-spin" /> : "Spara minne"}
            </button>
            <button onClick={() => setShowAddModal(false)} style={{border:'none', background:'none', marginTop:'10px', color:'#95A5A6', width:'100%'}}>Avbryt</button>
          </div>
        </div>
      )}
    </div>
  );
}

const btnStyle = { position: 'fixed', bottom: '90px', right: '20px', backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '15px 25px', borderRadius: '30px', fontWeight: 'bold', display:'flex', alignItems:'center', gap:'10px' };
const modalOverlay = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.8)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '25px', borderRadius: '20px', width: '85%', maxWidth: '400px' };
const inputStyle = { width: '100%', padding: '12px', marginBottom: '10px', borderRadius: '10px', border: '1px solid #EEE', boxSizing: 'border-box' };
const mediaBtn = { flex:1, display:'flex', alignItems:'center', justifyContent:'center', gap:'5px', padding:'12px', backgroundColor:'#F5F2ED', borderRadius:'10px', fontSize:'14px' };
const saveBtn = { width: '100%', padding: '15px', backgroundColor: '#2D5A27', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold' };

export default LogbookView;
